settings.custom_liquid:
{%- comment -%}
CozzyPaws • Instagram Reels (Custom Liquid block)
How to use:
1) Replace the URLs in reel_urls with your own Reel permalinks (comma-separated).
2) Keep the format https://www.instagram.com/reel/XXXXXXXX/  (the code adds trailing / if missing).
{%- endcomment -%}

{%- assign reel_urls = "
https://www.instagram.com/p/DPRuVu8jJXJ/,
https://www.instagram.com/p/DO3c5E2DXme/,
https://www.instagram.com/p/DO8iF4-isWl/
" | split: "," -%}

<style>
  .cp-ig-wrap { --cp-accent:#521010; margin: 0 auto; }
  .cp-ig-title { margin:0 0 .75rem; font-weight:700; font-size: clamp(1.1rem, 2.2vw, 1.5rem); 

}
  .cp-ig-grid { display:grid; gap:16px; grid-template-columns: repeat(3, minmax(0,1fr)); }
  @media(max-width: 990px){ .cp-ig-grid{ grid-template-columns: repeat(2, minmax(0,1fr)); } }
  @media(max-width: 749px){ .cp-ig-grid{ grid-template-columns: 1fr; } }
  .cp-ig-item .instagram-media{
    background:#fff;border:0;margin:0 auto;max-width:540px;width:100%;
    box-shadow:0 8px 24px rgba(0,0,0,.06); border-radius:12px; overflow:hidden;
  }
  .cp-ig-link{ text-align:center; margin:.5rem 0 0; }
  .cp-ig-link a{ text-decoration:none; border-bottom:2px solid var(--cp-accent); padding-bottom:2px; 
color: white;
}
</style>

<div class="cp-ig-wrap page-width">
  <h2 class="cp-ig-title">وداعاً للبلل والوسخ… ومرحبا بالنظافة والراحة 🛁🐶</h2>
  <div class="cp-ig-grid">
    {%- for raw in reel_urls -%}
      {%- assign clean = raw | strip | split:'?' | first -%}
      {%- if clean != "" -%}
        {%- assign last = clean | slice:-1,1 -%}
        {%- if last != '/' -%}{%- assign clean = clean | append:'/' -%}{%- endif -%}
        <div class="cp-ig-item">
          <blockquote class="instagram-media"
                      data-instgrm-permalink="{{ clean }}"
                      data-instgrm-version="14"></blockquote>
          <p class="cp-ig-link"><a href="{{ clean }}" target="_blank" rel="noopener">Voir sur Instagram</a></p>
        </div>
      {%- endif -%}
    {%- endfor -%}
  </div>
</div>

<script>
  (function(){
    function processIG(){ try{ if(window.instgrm && instgrm.Embeds && instgrm.Embeds.process){ instgrm.Embeds.process(); } }catch(e){} }
    if(!window.__cozzyIGLoaded){
      var s=document.createElement('script'); s.async=true; s.src="https://www.instagram.com/embed.js";
      s.onload=processIG; document.head.appendChild(s); window.__cozzyIGLoaded=true;
    } else { processIG(); }
  })();
</script>
